  ('Fire Safety Certificate', 'Obtain or renew fire safety certificates for commercial premises.', 'safety', 'annually', ARRAY['sole_trader', 'partnership', 'company', 'trust', 'cooperative'], ARRAY['NSW', 'VIC', 'QLD', 'SA', 'WA', 'TAS', 'NT', 'ACT'], '{}', 'Annual compliance', 'State Fire Authority', NULL),
  ('Liquor Licence Renewal', 'Renew your liquor licence if you sell or serve alcohol.', 'licensing', 'annually', ARRAY['sole_trader', 'partnership', 'company', 'trust', 'cooperative'], ARRAY['NSW', 'VIC', 'QLD', 'SA', 'WA', 'TAS', 'NT', 'ACT'], ARRAY['hospitality', 'retail'], 'Annual renewal', 'State Liquor Authority', NULL);
